'use strict';

const API_BASE = 'https://jsonplaceholder.typicode.com/posts';

function assertEl(sel) {
  const el = document.querySelector(sel);
  if (!el) console.error(`[busca] elemento não encontrado: ${sel}`);
  return el;
}

const elQ = assertEl('#q');
const btnCancel = assertEl('#cancel');
const elStatus = assertEl('#status');
const elSpinner = assertEl('#spinner');
const elLista = assertEl('#lista');
const elErro = assertEl('#erro');

const hasDom = Boolean(elQ && btnCancel && elStatus && elSpinner && elLista && elErro);

let currentJobId = 0;
let currentController = null;
let debounceId = null;

function setUi(state, msg) {
  if (!hasDom) return;
  elStatus.textContent = state;
  elSpinner.style.display = (state === 'loading') ? 'block' : 'none';
  elErro.textContent = '';
  if (state === 'error') elErro.textContent = String(msg ?? 'erro');
}

function renderLista(items) {
  if (!hasDom) return;
  elLista.innerHTML = '';
  for (const it of items) {
    const li = document.createElement('li');
    li.textContent = `#${it.id} — ${it.title}`;
    elLista.appendChild(li);
  }
}

async function fetchWithTimeout(url, options = {}, ms = 4000) {
  const controller = options.signal ? null : new AbortController();
  const signal = options.signal ?? controller.signal;
  const id = setTimeout(() => {
    if (controller) controller.abort();
  }, ms);

  try {
    return await fetch(url, { ...options, signal });
  } finally {
    clearTimeout(id);
  }
}

async function safeReadJson(res) {
  const text = await res.text().catch(() => '');
  try {
    return { ok: true, value: JSON.parse(text) };
  } catch {
    return { ok: false, msg: 'JSON inválido', raw: text };
  }
}

async function buscarAgora(termo) {
  if (!hasDom) return;

  // cancela request anterior
  if (currentController) currentController.abort();

  currentJobId += 1;
  const jobId = currentJobId;

  const controller = new AbortController();
  currentController = controller;

  const url = `${API_BASE}?q=${encodeURIComponent(termo)}`;

  setUi('loading');

  let res;
  try {
    res = await fetchWithTimeout(url, { signal: controller.signal, headers: { Accept: 'application/json' } }, 4000);
  } catch (e) {
    if (e && e.name === 'AbortError') return; // cancelado/timeout: ignora
    if (jobId !== currentJobId) return;
    setUi('error', 'erro de rede');
    return;
  }

  const parsed = await safeReadJson(res);

  if (jobId !== currentJobId) return;

  if (!res.ok) {
    const msg = parsed.ok ? (parsed.value?.error?.message ?? res.statusText) : (parsed.raw || res.statusText);
    setUi('error', `HTTP ${res.status}: ${msg}`);
    return;
  }

  if (!parsed.ok || !Array.isArray(parsed.value)) {
    setUi('error', 'formato inesperado');
    return;
  }

  setUi('success');
  renderLista(parsed.value.slice(0, 10));
}

function debounceBusca(termo) {
  if (debounceId !== null) clearTimeout(debounceId);
  debounceId = setTimeout(() => buscarAgora(termo), 300);
}

function onCancel() {
  if (currentController) currentController.abort();
  currentJobId += 1;
  setUi('idle');
  renderLista([]);
}

if (hasDom) {
  setUi('idle');
  elQ.addEventListener('input', () => {
    const termo = String(elQ.value ?? '').trim();
    if (termo.length === 0) {
      onCancel();
      return;
    }
    debounceBusca(termo);
  });
  btnCancel.addEventListener('click', onCancel);
}
